import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"认证机制：Session、Cookie、JWT、OAuth 2.0、OIDC 与 API Key","description":"","frontmatter":{},"headers":[],"relativePath":"05-backend-data/notes/06-api-database/05-authentication-mechanisms.md","filePath":"05-backend-data/notes/06-api-database/05-authentication-mechanisms.md","lastUpdated":null}'),s={name:"05-backend-data/notes/06-api-database/05-authentication-mechanisms.md"};function d(n,e,r,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="认证机制-session、cookie、jwt、oauth-2-0、oidc-与-api-key" tabindex="-1">认证机制：Session、Cookie、JWT、OAuth 2.0、OIDC 与 API Key <a class="header-anchor" href="#认证机制-session、cookie、jwt、oauth-2-0、oidc-与-api-key" aria-label="Permalink to &quot;认证机制：Session、Cookie、JWT、OAuth 2.0、OIDC 与 API Key&quot;">​</a></h1><p>认证回答“当前请求代表谁或哪个客户端”，授权回答“它能否对这个资源执行此操作”。认证凭据只是身份主张的输入；服务端仍要验证签名、有效期、受众、会话状态和撤销策略。</p><h2 id="_1-身份、客户端与令牌" tabindex="-1">1. 身份、客户端与令牌 <a class="header-anchor" href="#_1-身份、客户端与令牌" aria-label="Permalink to &quot;1. 身份、客户端与令牌&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    U[&quot;资源所有者 / 用户&quot;] --&gt; C[&quot;客户端&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; AS[&quot;授权服务器 / 身份提供方&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    AS --&gt;|&quot;access token&quot;| C</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|&quot;凭据 + 请求&quot;| RS[&quot;资源服务器 / API&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    RS --&gt;|&quot;认证主体 principal&quot;| AZ[&quot;授权决策&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>用户、客户端应用和访问令牌是不同对象。一个 token 可能代表用户、客户端自身，或二者的组合。API 不应仅看到 <code>sub</code> 就假定它是最终用户；要结合 issuer、audience、授权类型和声明定义。</p><h2 id="_2-session-与-cookie" tabindex="-1">2. Session 与 Cookie <a class="header-anchor" href="#_2-session-与-cookie" aria-label="Permalink to &quot;2. Session 与 Cookie&quot;">​</a></h2><h3 id="_2-1-服务端-session" tabindex="-1">2.1 服务端 Session <a class="header-anchor" href="#_2-1-服务端-session" aria-label="Permalink to &quot;2.1 服务端 Session&quot;">​</a></h3><p>登录成功后，服务端创建随机且不可预测的 session ID，把账户、创建时间、过期时间、认证强度和撤销状态保存到数据库或缓存。浏览器只持有 session ID：</p><div class="language-http vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Set-Cookie</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> __Host-session=RANDOM_256_BIT_VALUE; Path=/; Secure; HttpOnly; SameSite=Lax</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Cookie 属性：</p><ul><li><code>Secure</code>：仅通过安全传输发送；本身不加密 Cookie 内容。</li><li><code>HttpOnly</code>：阻止脚本通过 <code>document.cookie</code> 读取，不能阻止浏览器随请求发送。</li><li><code>SameSite=Strict|Lax|None</code>：限制跨站发送；<code>None</code> 必须配合 <code>Secure</code>。</li><li><code>Path</code>、<code>Domain</code>：控制发送范围，不是可靠的安全隔离边界；同源应用应避免互相覆盖。</li><li><code>Max-Age</code>/<code>Expires</code>：控制持久化；没有时通常是会话 Cookie。</li><li><code>__Host-</code> 前缀：要求 Secure、<code>Path=/</code> 且无 Domain，降低子域覆盖风险。</li></ul><p>session ID 只保存随机标识，不把角色、余额等可变可信状态放进未签名 Cookie。登录、提权和密码修改后轮换 ID，防止会话固定；登出在服务端撤销并清 Cookie。闲置过期与绝对过期分别限制长期风险。</p><p>Cookie 自动随请求发送，因此状态变更接口还需防 CSRF：SameSite 是一层防护，不能覆盖所有部署；可使用同步 token、双重提交 token、校验 Origin/Referer，并禁止用 GET 改状态。</p><h3 id="_2-2-cookie-内封装会话" tabindex="-1">2.2 Cookie 内封装会话 <a class="header-anchor" href="#_2-2-cookie-内封装会话" aria-label="Permalink to &quot;2.2 Cookie 内封装会话&quot;">​</a></h3><p>服务端也可把少量会话数据加密并认证后存入 Cookie，但撤销、权限变化、密钥轮换和 4 KiB 左右大小限制更复杂。签名只防篡改，不隐藏内容；敏感信息需要加密且仍应最小化。</p><h2 id="_3-jwt-的结构与验证" tabindex="-1">3. JWT 的结构与验证 <a class="header-anchor" href="#_3-jwt-的结构与验证" aria-label="Permalink to &quot;3. JWT 的结构与验证&quot;">​</a></h2><p>JWT 是 claims 的紧凑表示，常见 JWS 形式由 <code>base64url(header).base64url(payload).signature</code> 三段组成。payload 默认只是编码，不是加密，任何持有者都能读取。</p><p>常见声明：</p><table tabindex="0"><thead><tr><th>claim</th><th>意义</th><th>验证要求</th></tr></thead><tbody><tr><td><code>iss</code></td><td>签发者</td><td>与配置的精确 issuer 匹配</td></tr><tr><td><code>sub</code></td><td>主体标识</td><td>结合签发者解释，不单独全局唯一</td></tr><tr><td><code>aud</code></td><td>目标受众</td><td>API 必须是允许受众之一</td></tr><tr><td><code>exp</code></td><td>过期时间</td><td>当前时间不能超过，允许有限时钟偏差</td></tr><tr><td><code>nbf</code></td><td>不早于</td><td>未到时间拒绝</td></tr><tr><td><code>iat</code></td><td>签发时间</td><td>可用于异常检测，不自动保证新鲜</td></tr><tr><td><code>jti</code></td><td>token 标识</td><td>可用于撤销/重放控制，但需服务端状态</td></tr></tbody></table><p>验证顺序至少包括：限制 token 大小；只允许预配置算法；按受信 issuer 找密钥；验证签名；验证 <code>iss</code>、<code>aud</code>、时间；验证 token 类型和必要声明。不能接受 header 中任意 <code>alg</code>、<code>jku</code> 或 <code>kid</code> 指向攻击者密钥。<code>kid</code> 只是在受信任 JWKS 集合内选键。</p><p>JWT 的自包含不能替代撤销。短 access token 配合服务端检查高风险状态、密钥轮换和 refresh token 管理，通常比长寿命 JWT 安全。浏览器把 bearer token 放 <code>localStorage</code> 会暴露给同源 XSS；BFF 或安全 Cookie 会话可减少 token 暴露面，但仍需 XSS/CSRF 防护。</p><h2 id="_4-oauth-2-0-解决什么" tabindex="-1">4. OAuth 2.0 解决什么 <a class="header-anchor" href="#_4-oauth-2-0-解决什么" aria-label="Permalink to &quot;4. OAuth 2.0 解决什么&quot;">​</a></h2><p>OAuth 是委托授权框架：客户端在不取得用户密码的情况下获得受限 access token，访问资源服务器。它本身不定义“用户登录结果”；OIDC 在其上增加身份层。</p><h3 id="_4-1-authorization-code-pkce" tabindex="-1">4.1 Authorization Code + PKCE <a class="header-anchor" href="#_4-1-authorization-code-pkce" aria-label="Permalink to &quot;4.1 Authorization Code + PKCE&quot;">​</a></h3><p>现代浏览器、移动端和服务端 Web 客户端通常使用授权码流程并启用 PKCE：</p><ol><li>客户端生成随机 <code>code_verifier</code>，计算 <code>code_challenge</code>。</li><li>浏览器跳转授权端点，带 <code>state</code>、精确 <code>redirect_uri</code>、challenge 和所需 scope。</li><li>用户在授权服务器认证和授权。</li><li>授权服务器只把短寿命 code 返回已注册 redirect URI。</li><li>客户端后端/应用用 code、同一 redirect URI 和 verifier 换 token。</li><li>授权服务器验证 challenge，降低授权码被截获后的利用。</li></ol><p><code>state</code> 绑定发起请求、防 CSRF 和响应混淆；它必须随机、一次性并与浏览器会话关联，不能装入任意可跳转 URL。redirect URI 应精确匹配注册值，不使用开放重定向或宽泛通配符。</p><h3 id="_4-2-client-credentials" tabindex="-1">4.2 Client Credentials <a class="header-anchor" href="#_4-2-client-credentials" aria-label="Permalink to &quot;4.2 Client Credentials&quot;">​</a></h3><p>机器到机器调用可用客户端凭据获取代表客户端自身的 token。它不代表最终用户。client secret 只能由能保密的后端客户端持有，不能嵌入浏览器 JS、移动包或公开仓库。</p><h3 id="_4-3-refresh-token" tabindex="-1">4.3 Refresh Token <a class="header-anchor" href="#_4-3-refresh-token" aria-label="Permalink to &quot;4.3 Refresh Token&quot;">​</a></h3><p>refresh token 用于换取新 access token，价值通常更高，应只发送给授权服务器。对公开客户端使用轮换：每次换新 refresh token，旧 token 再次使用视为重放并撤销 token family。保存时加密/哈希、绑定客户端，设置闲置与绝对期限。</p><p>资源 API 不接受 refresh token。scope 表示授权范围，但最终资源级权限仍由 API 按主体、对象和租户判断。</p><h2 id="_5-openid-connect-oidc" tabindex="-1">5. OpenID Connect（OIDC） <a class="header-anchor" href="#_5-openid-connect-oidc" aria-label="Permalink to &quot;5. OpenID Connect（OIDC）&quot;">​</a></h2><p>OIDC 在 OAuth 授权请求中使用 <code>openid</code> scope，返回 ID Token 来描述认证事件和用户身份，并定义 UserInfo、发现文档等能力。</p><p>ID Token 的 <code>aud</code> 是客户端，不是普通资源 API；客户端验证 issuer、audience、签名、<code>exp</code>、<code>nonce</code>，多 audience 时还要按规范处理 <code>azp</code>。<code>nonce</code> 把 ID Token 绑定到发起的认证请求，防重放。ID Token 用于客户端确认登录，不应替代 access token 调 API。</p><p>发现文档通常位于 issuer 下的 <code>/.well-known/openid-configuration</code>，给出端点、JWKS URI、支持算法。生产配置应固定受信 issuer，并对发现/JWKS 设置缓存、轮换和故障策略，不从未验证 token 动态选择任意 issuer。</p><h2 id="_6-api-key" tabindex="-1">6. API Key <a class="header-anchor" href="#_6-api-key" aria-label="Permalink to &quot;6. API Key&quot;">​</a></h2><p>API key 常标识调用项目或机器客户端，适合服务间、开发者 API、配额和计费。它不天然证明最终用户，也不适合放 URL 查询参数，因为 URL 会进入历史、代理和日志。</p><p>推荐格式含公开前缀和高熵 secret，例如 <code>lili_live_&lt;key_id&gt;.&lt;secret&gt;</code>。服务端存 key ID 与 secret 的慢哈希/带密钥哈希、状态、scope、创建者、最后使用时间和过期时间；展示 secret 仅一次。支持双 key 轮换：先创建新 key、迁移、再撤销旧 key。</p><p>API key 通过 TLS 的请求头发送。日志只记录 key ID/前缀，绝不记录 secret。对高风险服务可使用 mTLS 或签名请求提供更强的客户端绑定和重放保护。</p><h2 id="_7-机制比较" tabindex="-1">7. 机制比较 <a class="header-anchor" href="#_7-机制比较" aria-label="Permalink to &quot;7. 机制比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>机制</th><th>服务端状态</th><th>撤销</th><th>浏览器风险</th><th>典型用途</th></tr></thead><tbody><tr><td>随机 Session ID + Cookie</td><td>有</td><td>立即</td><td>CSRF、XSS 间接操作</td><td>第一方 Web 登录</td></tr><tr><td>自包含 JWT access token</td><td>少</td><td>通常延迟到过期</td><td>token 被盗后的 bearer 风险</td><td>分布式 API 授权载体</td></tr><tr><td>OAuth access token</td><td>由授权系统管理</td><td>依 token 类型</td><td>流程配置与 token 存储风险</td><td>委托第三方/多客户端</td></tr><tr><td>OIDC ID Token</td><td>认证事件</td><td>不作为 API 会话撤销工具</td><td>错把它当 access token</td><td>客户端确认登录</td></tr><tr><td>API key</td><td>有</td><td>立即</td><td>公开客户端无法保密</td><td>机器/项目调用与配额</td></tr></tbody></table><p>没有“JWT 比 Session 更可扩展”的绝对结论。JWT 减少逐请求会话读取，却把撤销、声明过期、密钥轮换和体积成本转移到其他位置。选择要基于信任边界和撤销时效。</p><h2 id="_8-密码与多因素认证" tabindex="-1">8. 密码与多因素认证 <a class="header-anchor" href="#_8-密码与多因素认证" aria-label="Permalink to &quot;8. 密码与多因素认证&quot;">​</a></h2><p>密码只通过 TLS 接收，用专用密码哈希函数和每用户随机 salt 存储；参数需要可升级。不要加密后可逆保存，不使用通用快速哈希。登录接口做账户/IP/设备多维限速，错误文案避免账号枚举。</p><p>多因素提升认证强度。WebAuthn/passkey 使用公钥凭据并绑定 RP，能抵抗传统钓鱼；短信受 SIM 换卡和转发风险影响。高风险操作可要求最近认证时间或更强认证方法，提权后轮换 session。</p><h2 id="_9-完整案例-web-与-cli-共用订单-api" tabindex="-1">9. 完整案例：Web 与 CLI 共用订单 API <a class="header-anchor" href="#_9-完整案例-web-与-cli-共用订单-api" aria-label="Permalink to &quot;9. 完整案例：Web 与 CLI 共用订单 API&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>第一方 Web 使用同域 BFF；CLI 是公开客户端；合作方服务是机密客户端。</li><li>API 要知道用户/客户端、租户和 scope，并可在员工离职后尽快撤销。</li><li>access token 有效期 10 分钟，CLI 需要长期登录。</li></ul><h3 id="步骤" tabindex="-1">步骤 <a class="header-anchor" href="#步骤" aria-label="Permalink to &quot;步骤&quot;">​</a></h3><ol><li>Web 通过 OIDC authorization code + PKCE 登录，BFF 验证 ID Token 后创建服务端 session，并向浏览器设置 <code>__Host-session</code> Cookie。</li><li>BFF 在服务端持有 OAuth token，浏览器不接触 refresh token；写请求校验 CSRF token 与 Origin。</li><li>CLI 走适合设备/原生应用的标准授权流程，安全存储 refresh token，并使用轮换。</li><li>合作方使用 client credentials，token 主体是客户端而非员工。</li><li>API 验证 access token 的签名、issuer、audience、时间和 scope，再加载当前主体/租户状态进行授权。</li><li>离职时撤销 session 和 refresh token；短 access token 最迟在 10 分钟后失效，高风险接口额外检查账户状态。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>每个请求生成 principal：<code>subject</code>、<code>client_id</code>、<code>tenant_id</code>、<code>scopes</code>、<code>auth_time</code>。它只是授权输入，不直接把 token 内 <code>role=admin</code> 当永久真相。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>修改 JWT payload 后签名失败；错误 audience 和 issuer 均被拒绝。</li><li>access token 不能用于 OIDC 客户端会话，ID Token 不能调用订单 API。</li><li>Cookie 具备 Secure、HttpOnly、SameSite，登录后 session ID 轮换。</li><li>同一 refresh token 第二次使用触发 family 撤销。</li><li>日志和 URL 不含 token、Cookie 或 API secret。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若 API 只验证 JWT 签名而不验证 audience，签给另一个服务的 token 可能被错误接受。修正为每个资源服务器固定 issuer、audience、允许算法和 token 类型。若把管理员角色写入一年有效 JWT，降权无法及时生效；缩短令牌寿命，并对敏感权限查询受控授权状态。</p><h2 id="_10-常见错误" tabindex="-1">10. 常见错误 <a class="header-anchor" href="#_10-常见错误" aria-label="Permalink to &quot;10. 常见错误&quot;">​</a></h2><ul><li>用 Base64 当加密，认为 JWT payload 不可见。</li><li>接受 token 声明的任意算法或远程密钥 URL。</li><li>把 ID Token 发给资源 API。</li><li>在浏览器、移动应用或 Git 仓库嵌入 client secret/API key。</li><li>只清浏览器 Cookie、不撤销服务端 session。</li><li>Cookie 登录没有 CSRF 防护。</li><li>日志记录 Authorization 或 refresh token。</li><li>把 scope 当资源级授权，未验证对象所属租户。</li></ul><h2 id="_11-练习" tabindex="-1">11. 练习 <a class="header-anchor" href="#_11-练习" aria-label="Permalink to &quot;11. 练习&quot;">​</a></h2><p>为 Web、CLI 和定时任务设计认证方案，画出授权码 + PKCE 流程，列出每种凭据的存储位置、寿命、轮换、撤销和日志规则。</p><p>完成标准：能区分 access/refresh/ID token；JWT 验证包含 issuer/audience/time/algorithm；Cookie 会话防固定与 CSRF；API key 可双 key 轮换；离职与密钥泄露有可执行撤销路径；所有授权仍在 API 资源边界执行。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.rfc-editor.org/rfc/rfc9700.html" target="_blank" rel="noreferrer">RFC 9700: Best Current Practice for OAuth 2.0 Security</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc7636.html" target="_blank" rel="noreferrer">RFC 7636: Proof Key for Code Exchange</a>（访问日期：2026-07-17）</li><li><a href="https://openid.net/specs/openid-connect-core-1_0.html" target="_blank" rel="noreferrer">OpenID Connect Core 1.0</a>（访问日期：2026-07-17）</li><li><a href="https://www.rfc-editor.org/rfc/rfc7519.html" target="_blank" rel="noreferrer">RFC 7519: JSON Web Token</a>（访问日期：2026-07-17）</li><li><a href="https://httpwg.org/http-extensions/draft-ietf-httpbis-rfc6265bis.html" target="_blank" rel="noreferrer">RFC 6265bis: Cookies</a>（访问日期：2026-07-17）</li></ul>`,64)])])}const u=t(s,[["render",d]]);export{k as __pageData,u as default};
